<template>
  <v-app>
      <EmployeeNavbar/>
    <div>
      <v-content>
        <v-card-title>
          <v-spacer></v-spacer>
          <v-text-field
            v-model="search"
            append-icon="search"
            label="Search Leads"
            single-line
            hide-details
          ></v-text-field>
        </v-card-title>

        <v-data-table
          :headers="headers"
          :items="leads"
          :search="search"         
          row
          wrap
          class="elevation-1"
        >
          <template slot="items" slot-scope="props">
            <td class="text-xs-left">{{ props.item.name }}</td>
            <td class="text-xs-left" v-if="props.item.status">
              {{ props.item.status.text }}
            </td>
            <td class="text-xs-left" v-else>
              New 
            </td>           
            
            <td class="text-xs-left">{{ props.item.created_at }}</td>
            <td class="text-xs-left">{{ props.item.edited_at }}</td>
            
            <td class="text-xs-left" v-if="props.item.employeeSelect == 'Yes'" >
              {{ props.item.employeeName }}
            </td>
            <td class="text-xs-left" v-else>
              
            </td>

            <v-btn v-if="props.item.employeeSelect == 'No'" fab dark small color="green" @click="selectLeads(props.item.id)">
               <v-icon dark>done</v-icon>
            </v-btn>
            <v-btn v-else fab small>
               <v-icon dark>lock</v-icon>
            </v-btn>
           
          </template>
        </v-data-table>      

      
      </v-content>
    </div>
  </v-app>
</template>

<script>
import EmployeeNavbar from '@/components/employee/Navbar'
import db from '@/firebase/init'
import firebase from 'firebase'
import moment from 'moment'
export default {
  name:'CounselorLeads',
  components: {
     EmployeeNavbar
  },
  data(){
      return{
        currency:'',
        search: '',
        rowsPerPageItems: [8, 16, 24],
        pagination: {
        rowsPerPage: 8
        },
        counselorId:null,
        total_contacted_leads:'',
        total_qualified_leads:'',
        total_working_leads:'',
        total_proposal_sent_leads:'',
        leads:[],
        headers: [
         { text: 'Name', value: 'name', sortable: !1 },        
         { text: 'Status', value: 'status', sortable: !1 },         
         { text: 'Created At', value: 'created_at', sortable: !1 },
         { text: 'Edited At', value: 'edited_at', sortable: !1 },  
         { text: 'Employee', value: 'employeeName', sortable: !1 },
         { text: 'Select', value: 'action', sortable: !1 },
        ],
        account:[]

      }
  },
  methods:{      
      selectLeads(id){
        var db = firebase.firestore(); 
        let leadRef = db.collection('leads').doc(id);
          leadRef.update({            
            employeeSelect:"Yes",
            employeeId:this.employeeId,
            employeeName:this.account.name
          })        
         .then(() => {
            this.leads = this.leads.filter(lead => {
            return lead.id != id
            })
         })
        //this.completeSnackbar = true 
      }        

  },
  created(){

      // Current Counselor
      var user = firebase.auth().currentUser;
      if (user) {
          this.employeeId = user.uid
          //this.email = user.email
          this.userLoggedin = true;                
      } else {
          this.userLoggedin = false;            
      }
      
      // Empoloyee Profile Information        
      db.collection("employee").doc(this.employeeId).onSnapshot(doc =>{
        this.account = doc.data()          
      })

      // Show All Leads
      let ref = db.collection('leads').orderBy('timestamp', 'desc')

      ref.onSnapshot(snapshot => {
        snapshot.docChanges().forEach(change => {
          if(change.type == 'added'){
            let doc = change.doc
            this.leads.push({
              id:doc.id,
              name:doc.data().name,
              email:doc.data().email,
              phone:doc.data().phone,
              website:doc.data().website,
              country:doc.data().country,
              city:doc.data().city,
              company:doc.data().company,
              agentName:doc.data().agentName,
              employeeName:doc.data().employeeName,
              employeeSelect:doc.data().employeeSelect,
              designation:doc.data().designation,
              source:doc.data().source,
              status:doc.data().status,
              created_at:doc.data().created_date,
              edited_at:doc.data().edited_date,
              timestamp:doc.data().timestamp,
            })
          }
        })
      }) 


      // Total Contacted Leads
      db.collection('leads').where("status.text", "==", "Contacted")
     .get()
     .then(snapshot => {
           this.total_contacted_leads = snapshot.size;
      })

      // Total Qualified Leads
      db.collection('leads').where("status.text", "==", "Qualified")
     .get()
     .then(snapshot => {
           this.total_qualified_leads = snapshot.size;
      })

      // Total Working Leads
      db.collection('leads').where("status.text", "==", "Working")
     .get()
     .then(snapshot => {
           this.total_working_leads = snapshot.size;
      })

      // Total Proposal Sent Leads
      db.collection('leads').where("status.text", "==", "Proposal Sent")
     .get()
     .then(snapshot => {
           this.total_proposal_sent_leads = snapshot.size;
      })

      // If the user is not Counselor then redirect
      /*
      firebase.auth().onAuthStateChanged(user =>{
      if(user){
        user.getIdTokenResult().then(idTokenResult => {
        
          if(idTokenResult.claims.counselor == true){
              //return true;
              console.log("This is counselor");              
          }else{
              console.log("This is not counselor");
              firebase.auth().signOut()
              .then((user)=>{
                this.$router.replace('/counselor-signin')
                this.feedback = "Wrong username or password";
              });
          
          }
          
            console.log(idTokenResult.claims);            
          })
          }
        })
        */

  },
    
   
}
</script>

<style>
  .leads_item{
    padding:20px;
		-webkit-transition: all 0.5s;
		-moz-transition: all 0.5s;
		-ms-transition: all 0.5s;
		-o-transition: all 0.5s;
		transition: all 0.5s;
  }
  .leads_item:hover{
		box-shadow: 0 4px 8px 0 rgba(0, 0, 0, 0.5), 0 6px 20px 0 rgba(0, 0, 0, 0.39);
	}
td{
  text-align: center;
}
</style>



